// Get current date and format for various APIs
const now = new Date();
const dateInfo = {
  fullDate: now.toISOString().split('T')[0],
  month: String(now.getMonth() + 1).padStart(2, '0'),
  day: String(now.getDate()).padStart(2, '0'),
  year: now.getFullYear(),
  yearShort: String(now.getFullYear()).slice(-2),
  dayOfWeek: ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'][now.getDay()],
  yesterdayDate: new Date(now.getTime() - 24*60*60*1000).toISOString().split('T')[0],
  liturgicalDate: `${String(now.getMonth() + 1).padStart(2, '0')}${String(now.getDate()).padStart(2, '0')}${String(now.getFullYear()).slice(-2)}`,
  displayDate: `${now.getMonth() + 1}/${now.getDate()}/${now.getFullYear()}`
};

// Benedictine themes by day
const themes = {
  'Sunday': 'Worship & Community',
  'Monday': 'Humility & Simplicity', 
  'Tuesday': 'Stability',
  'Wednesday': 'Listening',
  'Thursday': 'Hospitality & Kindness',
  'Friday': 'Sacrifice & Repentance',
  'Saturday': 'Rest & Beauty'
};

dateInfo.benedictineTheme = themes[dateInfo.dayOfWeek];

return dateInfo;

