// Process all the gathered data
const dateInfo = $('Format Date & Theme').item.json;

// Parse xAI responses
let readings, reflection, history;
try {
  const readingsResponse = $('xAI - Process Readings').item.json.choices[0].message.content;
  readings = JSON.parse(readingsResponse);
} catch (e) {
  readings = { readings: [], saint: { name: 'Saint of the Day', description: 'Information unavailable' }};
}

try {
  const reflectionResponse = $('xAI - Benedictine Reflection').item.json.choices[0].message.content;
  reflection = JSON.parse(reflectionResponse);
} catch (e) {
  reflection = { overview: 'Reflection unavailable', challenge: 'Challenge unavailable', prayer: 'Prayer unavailable' };
}

try {
  const historyResponse = $('xAI - Historical Facts').item.json.choices[0].message.content;
  history = JSON.parse(historyResponse);
} catch (e) {
  history = [];
}

// Process Dodgers info from Tavily
let gameInfo = 'No game yesterday';
let gameLink = 'https://www.mlb.com/dodgers';

const tavilyData = $('Tavily - Dodgers Search').item.json;
if (tavilyData?.results && Array.isArray(tavilyData.results) && tavilyData.results.length > 0) {
  const gameResult = tavilyData.results[0];
  gameInfo = gameResult.content || gameResult.title || 'Game information unavailable';
  gameLink = gameResult.url || 'https://www.mlb.com/dodgers';
}

// Process MLB standings
let dodgersStandings = 'Standings unavailable';
const standings = $('MLB API - Standings').item.json;

if (standings?.records?.[0]?.teamRecords) {
  const nlWest = standings.records[0].teamRecords;
  const dodgers = nlWest.find(team => team.team.name === 'Los Angeles Dodgers');

  if (dodgers) {
    const position = dodgers.divisionRank;
    const record = `${dodgers.wins}-${dodgers.losses}`;
    const gb = dodgers.gamesBack === '-' ? '0' : dodgers.gamesBack;

    if (position === '1') {
      const secondPlace = nlWest.find(team => team.divisionRank === '2');
      const gamesAhead = secondPlace ? secondPlace.gamesBack : '0';
      dodgersStandings = `Dodgers (${record}) - 1st in NL West, ${gamesAhead} games ahead`;
    } else {
      dodgersStandings = `Dodgers (${record}) - ${position} in NL West, ${gb} GB`;
    }
  }
}

// Compile beautiful HTML email
const emailSubject = `Daily Reflection - ${dateInfo.dayOfWeek}, ${dateInfo.liturgicalDate}`;

const emailBody = `
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${emailSubject}</title>
</head>
<body style="margin: 0; padding: 0; font-family: 'Georgia', 'Times New Roman', serif; background-color: #f5f5f0;">
  <div style="max-width: 600px; margin: 0 auto; background-color: #ffffff; box-shadow: 0 0 20px rgba(0,0,0,0.1);">

    <!-- Header -->
    <div style="background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); color: white; padding: 30px 20px; text-align: center;">
      <h1 style="margin: 0; font-size: 28px; font-weight: normal; letter-spacing: 1px;">Daily Reflection</h1>
      <p style="margin: 10px 0 0 0; font-size: 18px; opacity: 0.95;">${dateInfo.dayOfWeek}, ${dateInfo.displayDate}</p>
    </div>

    <!-- Main Content -->
    <div style="padding: 30px 25px;">

      <!-- Readings Section -->
      <div style="margin-bottom: 35px;">
        <h2 style="color: #4a5568; font-size: 20px; border-bottom: 2px solid #e2e8f0; padding-bottom: 8px; margin-bottom: 15px;">
          📖 Today's Readings
        </h2>
        ${readings.readings.map(r => `
        <div style="background-color: #f7fafc; border-left: 3px solid #667eea; padding: 12px 15px; margin-bottom: 12px;">
          <strong style="color: #2d3748; font-size: 16px;">${r.reference}</strong>
          <p style="margin: 8px 0 0 0; color: #4a5568; line-height: 1.6; font-size: 14px;">${r.context}</p>
        </div>`).join('')}
        <p style="margin-top: 15px; text-align: center;">
          <a href="https://bible.usccb.org/bible/readings/${dateInfo.liturgicalDate}.cfm" 
             style="color: #667eea; text-decoration: none; font-size: 14px; border-bottom: 1px dotted #667eea;">
            Verify today's readings at USCCB.org →
          </a>
        </p>
      </div>

      <!-- Saint of the Day -->
      <div style="margin-bottom: 35px;">
        <h2 style="color: #4a5568; font-size: 20px; border-bottom: 2px solid #e2e8f0; padding-bottom: 8px; margin-bottom: 15px;">
          ✝️ Saint of the Day
        </h2>
        <div style="background-color: #fef5e7; border-radius: 8px; padding: 15px;">
          <h3 style="margin: 0 0 10px 0; color: #764ba2; font-size: 18px;">${readings.saint.name}</h3>
          <p style="margin: 0 0 12px 0; color: #4a5568; line-height: 1.7; font-size: 14px;">${readings.saint.description}</p>
          <a href="https://en.wikipedia.org/wiki/${readings.saint.name.replace(/ /g, '_')}" 
             style="color: #667eea; text-decoration: none; font-size: 14px; border-bottom: 1px dotted #667eea;">
            Learn more on Wikipedia →
          </a>
        </div>
      </div>

      <!-- Benedictine Reflection -->
      <div style="margin-bottom: 35px;">
        <h2 style="color: #4a5568; font-size: 20px; border-bottom: 2px solid #e2e8f0; padding-bottom: 8px; margin-bottom: 15px;">
          🕊️ Benedictine Reflection: ${dateInfo.benedictineTheme}
        </h2>
        <div style="background: linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%); border-radius: 8px; padding: 20px;">
          <div style="margin-bottom: 15px;">
            <h4 style="margin: 0 0 8px 0; color: #2d3748; font-size: 14px; text-transform: uppercase; letter-spacing: 1px;">Overview</h4>
            <p style="margin: 0; color: #4a5568; line-height: 1.7; font-size: 14px;">${reflection.overview}</p>
          </div>
          <div style="background-color: rgba(255,255,255,0.7); border-radius: 6px; padding: 12px;">
            <h4 style="margin: 0 0 8px 0; color: #764ba2; font-size: 14px; text-transform: uppercase; letter-spacing: 1px;">Daily Challenge</h4>
            <p style="margin: 0; color: #4a5568; line-height: 1.6; font-size: 14px; font-weight: 500;">${reflection.challenge}</p>
          </div>
        </div>
      </div>

      <!-- Prayer -->
      <div style="margin-bottom: 35px;">
        <h2 style="color: #4a5568; font-size: 20px; border-bottom: 2px solid #e2e8f0; padding-bottom: 8px; margin-bottom: 15px;">
          🙏 Prayer for Today
        </h2>
        <div style="text-align: center; padding: 20px; background-color: #faf5ff; border-radius: 8px;">
          <p style="margin: 0; color: #553c9a; line-height: 1.8; font-size: 15px; font-style: italic;">
            ${reflection.prayer.replace(/\n/g, '<br/>')}
          </p>
        </div>
      </div>

      <!-- Historical Facts -->
      <div style="margin-bottom: 35px;">
        <h2 style="color: #4a5568; font-size: 20px; border-bottom: 2px solid #e2e8f0; padding-bottom: 8px; margin-bottom: 15px;">
          📅 On This Day in History
        </h2>
        <ul style="margin: 0; padding: 0; list-style: none;">
          ${history.map(h => `
          <li style="margin-bottom: 10px; padding-left: 25px; position: relative; color: #4a5568; line-height: 1.6; font-size: 14px;">
            <span style="position: absolute; left: 0; color: #667eea; font-weight: bold;">${h.year}:</span>
            <span style="display: inline-block; margin-left: 50px;">${h.fact}</span>
          </li>`).join('')}
        </ul>
      </div>

      <!-- Dodgers Update -->
      <div style="margin-bottom: 30px;">
        <h2 style="color: #4a5568; font-size: 20px; border-bottom: 2px solid #e2e8f0; padding-bottom: 8px; margin-bottom: 15px;">
          ⚾ Dodgers Update
        </h2>
        <div style="background: linear-gradient(135deg, #005a9c 0%, #003d6b 100%); color: white; border-radius: 8px; padding: 20px;">
          <div style="margin-bottom: 12px;">
            <strong style="display: inline-block; width: 100px; font-size: 13px; opacity: 0.9;">Previous Game:</strong>
            <span style="font-size: 14px;">${gameInfo}</span>
          </div>
          <div style="margin-bottom: 15px;">
            <strong style="display: inline-block; width: 100px; font-size: 13px; opacity: 0.9;">Standings:</strong>
            <span style="font-size: 14px; font-weight: 600;">${dodgersStandings}</span>
          </div>
          <div style="text-align: center; margin-top: 18px;">
            <a href="${gameLink}" 
               style="display: inline-block; background-color: white; color: #005a9c; padding: 10px 25px; border-radius: 25px; text-decoration: none; font-weight: 600; font-size: 14px;">
              Read Full Game Recap →
            </a>
          </div>
        </div>
      </div>

    </div>

    <!-- Footer -->
    <div style="background-color: #f7fafc; padding: 25px; text-align: center; border-top: 1px solid #e2e8f0;">
      <p style="margin: 0; color: #718096; font-size: 16px; font-style: italic; line-height: 1.6;">
        "Always we begin again"<br/>
        <span style="font-size: 14px; font-style: normal;">- St. Benedict</span>
      </p>
      <p style="margin: 15px 0 0 0; color: #a0aec0; font-size: 12px;">
        Daily Reflection • Benedictine Spirituality • Los Angeles Dodgers
      </p>
    </div>

  </div>
</body>
</html>
`;

return {
  subject: emailSubject,
  html: emailBody,
  text: emailBody.replace(/<[^>]*>/g, ''),
  timestamp: new Date().toISOString()
};
